	var actor: BattleActor = unit.get("actor") as BattleActor
	if marker == null or actor == null:
		return _get_unit_hurtbox_rect(unit)
	var feet_pos: Vector2 = marker.global_position
	if _attack_fx_root != null and is_instance_valid(_attack_fx_root):
		feet_pos = _attack_fx_root.to_local(feet_pos)
	var frame_size: Vector2 = _get_actor_battle_frame_size(actor) * battle_sprite_scale.abs()
	if frame_size == Vector2.ZERO:
		return _get_unit_hurtbox_rect(unit)
	var width: float = maxf(frame_size.x * 0.7, 24.0)
	var height: float = maxf(frame_size.y * 0.3, 20.0)
	var left: float = feet_pos.x - width * 0.5
	var top: float = feet_pos.y - frame_size.y * 0.45
	return Rect2(Vector2(left, top), Vector2(width, height))


