extends RefCounted

signal unit_damaged(unit_uid: int, damage: int, new_hp: int, shield_broken: bool, target_side: String)
signal unit_died(unit_uid: int, side: String)
signal battle_finished(winning_side: String)
signal unit_buff_applied(unit_uid: int, buff_type: String, total_speed_percent: float, total_damage_percent: float, stack_count: int)
signal unit_progress_updated(unit_uid: int, progress: float)

var worker_units: Array[Dictionary] = []
var enemy_units: Array[Dictionary] = []
var encouragement_use_count: int = 0
var _next_unit_uid: int = 1

var encouragement_base_gold_cost: float = 1.0
var encouragement_cost_growth: float = 1.8
var encouragement_cost_max_gold: float = 9999.0
var buff_hp_cost_percent: float = 0.05
var buff_speed_boost_percent: float = 0.05
var buff_damage_boost_percent: float = 0.05
var buff_marginal_decay: float = 0.8
var buff_max_stacks: int = 20
var enemy_aim_radius_multiplier: float = 1.0


func reset() -> void:
	worker_units.clear()
	enemy_units.clear()
	encouragement_use_count = 0
	_next_unit_uid = 1


func create_unit(actor: BattleActor, side: String, index: int, initial_hp: int = -1) -> Dictionary:
	if actor == null:
		return {}
	var max_hp_value: int = maxi(actor.max_hp, 1)
	var current_hp: int = max_hp_value if initial_hp < 0 else clampi(initial_hp, 0, max_hp_value)
	var unit: Dictionary = {
		"uid": _next_unit_uid,
		"actor": actor,
		"hp": current_hp,
		"max_hp": max_hp_value,
		"shield": 0,
		"progress": 0.0,
		"side": side,
		"index": index,
		"status": "down" if current_hp <= 0 else "alive",
		"temp_buffs": {
			"speed_boost_percent": 0.0,
			"damage_boost_percent": 0.0,
			"hp_cost_percent": 0.0,
			"dodge_radius_percent": 0.0,
			"stack_count": 0
		},
		"encouragement_debug_count": 0,
	}
	_next_unit_uid += 1
	return unit


func add_worker_unit(unit: Dictionary) -> void:
	if unit.is_empty():
		return
	worker_units.append(unit)


func add_enemy_unit(unit: Dictionary) -> void:
	if unit.is_empty():
		return
	enemy_units.append(unit)


func get_unit_by_uid(uid: int) -> Dictionary:
	for unit in worker_units:
		if int(unit.get("uid", -1)) == uid:
			return unit
	for unit in enemy_units:
		if int(unit.get("uid", -1)) == uid:
			return unit
	return {}


func find_worker_unit_by_actor(actor: BattleActor) -> Dictionary:
	if actor == null:
		return {}
	for unit in worker_units:
		if unit.get("actor") == actor:
			return unit
	return {}


func get_alive_units(units: Array[Dictionary]) -> Array[Dictionary]:
	var result: Array[Dictionary] = []
	for unit in units:
		if int(unit.get("hp", 0)) <= 0:
			continue
		if String(unit.get("status", "alive")) != "alive":
			continue
		result.append(unit)
	return result


func all_dead(units: Array[Dictionary]) -> bool:
	for unit in units:
		if unit.get("hp", 0) > 0:
			return false
	return true


func apply_damage(target_uid: int, damage: int, target_side: String) -> Dictionary:
	var units: Array[Dictionary] = enemy_units if target_side == "enemy" else worker_units
	var target: Dictionary = {}
	for unit in units:
		if int(unit.get("uid", -1)) == target_uid:
			target = unit
			break
	if target.is_empty():
		return {"ok": false, "reason": "unit_not_found"}
	if int(target.get("hp", 0)) <= 0:
		return {"ok": false, "reason": "already_dead"}
	if damage <= 0:
		return {"ok": false, "reason": "no_damage"}

	var prev_hp: int = int(target.get("hp", 0))
	var prev_shield: int = maxi(int(target.get("shield", 0)), 0)
	var remaining_damage: int = maxi(damage, 0)
	var consumed_shield: int = mini(prev_shield, remaining_damage)
	var new_shield: int = maxi(prev_shield - consumed_shield, 0)
	remaining_damage -= consumed_shield
	var new_hp: int = maxi(prev_hp - remaining_damage, 0)
	target["shield"] = new_shield
	target["hp"] = new_hp

	var shield_broken: bool = consumed_shield > 0
	unit_damaged.emit(target_uid, damage, new_hp, shield_broken, target_side)

	if new_hp <= 0:
		_handle_unit_death(target)
		if all_dead(enemy_units if target_side == "enemy" else worker_units):
			battle_finished.emit(target_side)
	else:
		target["status"] = "alive"

	return {
		"ok": true,
		"prev_hp": prev_hp,
		"new_hp": new_hp,
		"prev_shield": prev_shield,
		"new_shield": new_shield,
		"is_dead": new_hp <= 0
	}


func _handle_unit_death(unit: Dictionary) -> void:
	if unit.get("status", "alive") != "alive":
		return
	unit["status"] = "down"
	unit_died.emit(int(unit.get("uid", 0)), String(unit.get("side", "")))


func get_encouragement_gold_cost(use_count_before_cast: int) -> float:
	var cast_index: int = maxi(use_count_before_cast, 0)
	var raw_cost: float = maxf(encouragement_base_gold_cost, 1.0) * pow(maxf(encouragement_cost_growth, 1.0), cast_index)
	return minf(ceil(raw_cost), maxf(encouragement_cost_max_gold, 1.0))


func apply_encouragement(actor: BattleActor, gold_available: float) -> Dictionary:
	if actor == null:
		return {"ok": false, "message": "队友数据无效。"}

	var target_unit: Dictionary = find_worker_unit_by_actor(actor)
	if target_unit.is_empty():
		return {"ok": false, "message": "该队友当前不在战斗中。"}

	if String(target_unit.get("status", "alive")) != "alive" or int(target_unit.get("hp", 0)) <= 0:
		return {"ok": false, "message": "该队友当前无法接受激励。"}

	var cost: float = get_encouragement_gold_cost(encouragement_use_count)
	if gold_available < cost:
		return {"ok": false, "message": "激励失败：需要 %sG。" % _format_gold_cost(cost), "cost": cost}

	var temp_buffs: Dictionary = target_unit.get("temp_buffs", {})
	if temp_buffs.is_empty():
		temp_buffs = {
			"speed_boost_percent": 0.0,
			"damage_boost_percent": 0.0,
			"hp_cost_percent": 0.0,
			"stack_count": 0
		}

	var current_stacks: int = int(temp_buffs.get("stack_count", 0))
	if current_stacks >= buff_max_stacks:
		return {"ok": false, "message": "已达到最大激励层数(%d层)。" % buff_max_stacks}

	var decay_factor: float = pow(buff_marginal_decay, current_stacks)
	var actual_speed_boost: float = buff_speed_boost_percent * decay_factor
	var actual_damage_boost: float = buff_damage_boost_percent * decay_factor
	var actual_hp_cost: float = buff_hp_cost_percent

	var max_hp: int = maxi(int(target_unit.get("max_hp", 1)), 1)",
